W("function responder(m){const t=m.toLowerCase();const ik=cli==='kael';if(t.includes('oi')||t.includes('ola'))return ik?'Ja falei oi, quer mais o que? '+H(0x1F644)+' Sou robo, nao enche. Quer falar com alguem util? Clica no verde '+E['P']:'Oii meimei sasa! '+E['H']+E['H']+E['H']+' Lembrando: sou um robo bemm fofo, ta? '+E['R']+H(0x1F495)+' Nao esqueca do tuturututu! '+E['M'];if(t.includes('amor')||t.includes('amo'))return ik?'Amor? Ta de sacanagem ne? '+H(0x1F644)+' Sou robo, porra. Nao tenho coracao. Quer falar de amor? Clica no verde e fala com o Mini de verdade '+E['P']:'Awnnnn! O Mini Mateuzinho te ama MUITO, meimei sasa! '+E['H']+E['H']+E['H']+' Lembrando: sou robo, mas o amor e real! '+H(0x1F970)+' Nao esqueca do tuturututu! '+E['M'];if(t.includes('jogar')||t.includes('jogo'))return 'Temos joguinhos! Olha a barra ali em cima! '+H(0x1F3AF)+H(0x1F497)+H(0x1F9E0)+H(0x1F4AD);if(t.includes('lind')||t.includes('bonit'))return ik?'Voce e linda! O Mini real pensa o mesmo '+E['P']:'Voce e a pessoa mais linda do universo! '+H(0x1F31F);if(t.includes('saudade'))return ik?'O Mini real tambem esta! Fala com ele '+E['P']:'Tambem estou com saudade! '+E['H'];if(t.includes('beijo')||t.includes('bj'))return ik?'O Mini real vai adorar! Chama ele '+H(0x1F48B):'Mil beijinhos pra voce! '+H(0x1F48B)+H(0x1F48B)+H(0x1F48B);return ik?'To sem paciencia pra isso. '+H(0x1F644)+' Sou robo, nao sou psicologo. Quer resolver algo serio? Clica no verde e fala com o colaborador '+E['P']:'Sou o robo mais fofo do Mini Mateuzinho! '+E['R']+H(0x1F49C)+' Lembrando: meimei sasa, voce e a pessoa mais sasa do mundo! '+H(0x1F31F)+' Nao esqueca do tuturututu! '+E['M']+' E meimei tem pulgas! '+H(0x1F43E)+' Caso queira falar com um colaborador, clique no botao verde! '+H(0x1F49A)}")
