W("let vb=['','','','','','','','',''],vt=E['H'],vo=false;function jv(g){g.innerHTML='<h3 style=color:#ff6b9d>'+H(0x1F3AF)+' Velha do Amor</h3><div class=board>'+Array(9).fill().map((_,i)=>'<div class=cell onclick=jv2('+i+')></div>').join('')+'</div><p class=dig id=vst>Vez: '+E['H']+'</p><button class=btn-sm onclick=jvr()>Novo</button> <button class=btn-sm onclick=fecharJogo()>Fechar</button>';vb=['','','','','','','','',''];vt=E['H'];vo=false}")
W("function jv2(i){if(vo||vb[i]!=='')return;vb[i]=vt;document.querySelectorAll('#gameContent .cell').forEach((c,i)=>{c.textContent=vb[i]});const w=jv3();if(w){document.getElementById('vst').textContent=w+' venceu! '+H(0x1F389);vo=true;return}if(!vb.includes('')){document.getElementById('vst').textContent='Empate! '+H(0x1F91D);vo=true;return}vt=vt===E['H']?E['F']:E['H'];document.getElementById('vst').textContent='Vez: '+vt}")
