W("function jc2(){if(ca)return;ca=true;cc=0;let t=15;ct=setInterval(()=>{t--;document.getElementById('hs').textContent='Clicks: '+cc+' | '+t+'s';if(t<=0){clearInterval(ct);ca=false;document.getElementById('hs').textContent='Fim! '+cc+' '+E['H']+(cc>=15?' Incrivel! '+H(0x1F31F)+H(0x1F31F):'')}},1000);jc3()}")
